function solve(nums) {
    const n = nums.length;
    if (n === 1) return 0;

    // Precompute primes up to the maximum number in nums using Sieve of Eratosthenes
    const maxNum = Math.max(...nums);
    const isPrime = new Array(maxNum + 1).fill(true);
    isPrime[0] = isPrime[1] = false;
    for (let i = 2; i * i <= maxNum; i++) {
        if (isPrime[i]) {
            for (let j = i * i; j <= maxNum; j += i) {
                isPrime[j] = false;
            }
        }
    }

    // Build a map from primes to their multiples' indices
    const primeToIndices = new Map();
    for (let i = 0; i < n; i++) {
        const num = nums[i];
        if (isPrime[num]) {
            if (!primeToIndices.has(num)) {
                primeToIndices.set(num, []);
            }
            primeToIndices.get(num).push(i);
        }
    }

    // BFS setup
    const queue = [[0, 0]];
    const visited = new Set();
    visited.add(0);

    while (queue.length > 0) {
        const [current, steps] = queue.shift();

        // Check if we've reached the end
        if (current === n - 1) {
            return steps;
        }

        // Move to adjacent indices
        const neighbors = [];
        if (current + 1 < n) neighbors.push(current + 1);
        if (current - 1 >= 0) neighbors.push(current - 1);

        for (const neighbor of neighbors) {
            if (!visited.has(neighbor)) {
                visited.add(neighbor);
                queue.push([neighbor, steps + 1]);
            }
        }

        // Check for prime teleportation
        const num = nums[current];
        if (isPrime[num]) {
            const indices = primeToIndices.get(num) || [];
            for (const index of indices) {
                if (index !== current && !visited.has(index)) {
                    visited.add(index);
                    queue.push([index, steps + 1]);
                }
            }
        }
    }

    return -1; // In case it's unreachable (though problem says it's possible)
}

