#include <vector>
#include <queue>
#include <unordered_map>
#include <unordered_set>
#include <algorithm>

using namespace std;

vector<bool> sieve(int max_num) {
    vector<bool> is_prime(max_num + 1, true);
    is_prime[0] = is_prime[1] = false;
    for (int i = 2; i * i <= max_num; ++i) {
        if (is_prime[i]) {
            for (int j = i * i; j <= max_num; j += i) {
                is_prime[j] = false;
            }
        }
    }
    return is_prime;
}

long long solve(std::vector<long long> nums) {
    int n = nums.size();
    if (n == 1) return 0;

    int max_num = *max_element(nums.begin(), nums.end());
    vector<bool> is_prime = sieve(max_num);

    unordered_map<long long, vector<int>> prime_to_indices;
    for (int i = 0; i < n; ++i) {
        long long num = nums[i];
        if (is_prime[num]) {
            prime_to_indices[num].push_back(i);
        }
    }

    queue<pair<int, int>> q;
    unordered_set<int> visited;
    q.push({0, 0});
    visited.insert(0);

    while (!q.empty()) {
        auto [current, steps] = q.front();
        q.pop();

        if (current == n - 1) {
            return steps;
        }

        // Move to adjacent indices
        if (current + 1 < n && visited.find(current + 1) == visited.end()) {
            visited.insert(current + 1);
            q.push({current + 1, steps + 1});
        }
        if (current - 1 >= 0 && visited.find(current - 1) == visited.end()) {
            visited.insert(current - 1);
            q.push({current - 1, steps + 1});
        }

        // Check for prime teleportation
        long long num = nums[current];
        if (is_prime[num]) {
            for (int index : prime_to_indices[num]) {
                if (index != current && visited.find(index) == visited.end()) {
                    visited.insert(index);
                    q.push({index, steps + 1});
                }
            }
        }
    }

    return -1;
}
